class CircularQueue:
 def __init__(self, size):
 self.size = size
 self.front = self.rear = -1
 self.queue = [None] * size

 def enqueue(self, data):
 if (self.rear + 1) % self.size == self.front:
 print("Queue is full")
 elif self.front == -1:
 self.front = self.rear = 0
 self.queue[self.rear] = data
 else:
 self.rear = (self.rear + 1) % self.size
 self.queue[self.rear] = data

 def dequeue(self):
 if self.front == -1:
 print("Queue is empty")
 elif self.front == self.rear:
 temp = self.queue[self.front]
 self.front = self.rear = -1
 return temp
 else:
 temp = self.queue[self.front]
 self.front = (self.front + 1) % self.size
 return temp

#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
 int data;
 int priority;
} Node;

void heapify(Node* heap, int n, int i) {
 int largest = i;
 int left = 2 * i + 1;
 int right = 2 * i + 2;

 if (left < n && heap[left].priority > heap[largest].priority)
 largest = left;

 if (right < n && heap[right].priority > heap[largest].priority)
 largest = right;

 if (largest != i) {
 Node temp = heap[i];
 heap[i] = heap[largest];
 heap[largest] = temp;
 heapify(heap, n, largest);
 }
}

void insert(Node* heap, int* n, int data, int priority) {
 heap[*n].data = data;
 heap[*n].priority = priority;
 *n = *n + 1;
 heapify(heap, *n, *n - 1);
}

int extractMax(Node* heap, int* n) {
 if (*n == 0)
 return -1;
 int max = heap[0].data;
 heap[0] = heap[*n - 1];
 *n = *n - 1;
 heapify(heap, *n, 0);
 return max;
}
